import { successResponse, errorResponse, outputAndExit } from '@/cli/output';

import { search } from '@/operations/search';
import { getWalletOrExit } from '../lib/get-wallet-or-exit';

import type { Command } from '@/types';
import type { SearchInput } from '@/operations/search';

const SURFACE = 'cli:search';

export const searchCommand: Command<SearchInput> = async input => {
  const wallets = await getWalletOrExit(input);

  const result = await search(
    {
      query: input.query,
      broad: input.broad,
      limit: input.limit,
      page: input.page,
    },
    { surface: SURFACE, wallets, flags: input }
  );

  if (!result.success) {
    return outputAndExit(
      errorResponse({
        code: 'GENERAL_ERROR',
        message: result.message,
        surface: SURFACE,
        cause: result.cause,
      }),
      input
    );
  }

  return outputAndExit(successResponse(result), input);
};
